/**
 * @fileoverview Avatar view — DOM setup.
 * @module module/Avatar/view
 */

import { CLS, PART } from './constants.js';

/**
 * Build avatar DOM.
 */
export function setupDOM(root, config) {
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    if (config.square) {
        root.addClass(CLS.SQUARE);
    }

    // Size class
    if (config.size && config.size !== 'md') {
        root.addClass(`avatar-${config.size}`);
    }

    let $image = null;
    let $initials = null;

    if (config.src) {
        $image = PART.IMAGE.create({
            src: config.src,
            alt: config.alt || '',
            draggable: false,
        });
        root.append($image);

        // Fallback to initials on error
        if (config.initials) {
            $image.on('error', () => {
                $image.hide();
                if (!$initials) {
                    $initials = _createInitials(root, config.initials);
                }
                $initials.show();
            }, { once: true });
        }
    }

    if (config.initials && !config.src) {
        $initials = _createInitials(root, config.initials);
    }

    return { $image, $initials };
}

function _createInitials($parent, text) {
    const $span = PART.INITIALS.create({ 'aria-hidden': 'true' })
        .text(text.slice(0, 2));
    $parent.append($span);
    return $span;
}
