/**
 * @fileoverview Avatar constants.
 * @module module/Avatar/constants
 */

import { defineParts } from '../shared/definePart.js';
import { TRANSITION_COLORS } from '../shared/styleFragments.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:     'avatar',
    IMAGE:    'avatar-image',
    INITIALS: 'avatar-initials',
    GROUP:    'avatar-group',
    SQUARE:   'is-square',
});

export const DEFAULTS = Object.freeze({
    src: null,
    initials: '',
    alt: '',
    square: false,
    size: 'md',          // xs | sm | md | lg | xl
});

export const PART = defineParts('Avatar', {
    ROOT:     { class: 'avatar-root', aliases: ['root', 'avatar'] },
    IMAGE:    { class: 'avatar-image', aliases: ['image', 'img'], tag: 'img' },
    INITIALS: { class: 'avatar-initials', aliases: ['initials', 'fallback'], tag: 'span' },
    GROUP:    { class: 'avatar-group', aliases: ['group'] },
});

PART.ROOT.jit     = `inline-flex items-center justify-center overflow-hidden bg-[var(--av-bg)] fg-[var(--av-text)] rounded-[var(--av-radius)] w-[var(--av-size)] h-[var(--av-size)] text-[var(--av-font-size)] font-medium select-none shrink-0 [vertical-align:middle] ${TRANSITION_COLORS} {is-square}:rounded-[var(--av-square-radius)]`;
PART.IMAGE.jit    = 'w-full h-full [object-fit:cover]';
PART.INITIALS.jit = 'leading-none uppercase';
PART.GROUP.jit    = 'inline-flex items-center';

// Group → child avatar ring/overlap
PART.GROUP.bindContainsJIT('.avatar', 'ring-[2px] [ring-color:var(--av-ring)] [-ml:var(--av-group-overlap)]');
